import React, { useEffect, useState } from 'react';
import { Card, CardContent, Grid, TextField, Button, Typography, Stack, Alert } from '@mui/material';
import { getConfig, saveConfig } from '../../services/api';

function Settings() {
  const [form, setForm] = useState({
    ftp_host: '',
    ftp_port: '21',
    ftp_user: '',
    ftp_password: '',
    ftp_path: '/',
    drive_folder: 'CCTV_Backup',
    sync_interval: '60',
  });
  const [status, setStatus] = useState('');

  useEffect(() => {
    const loadConfig = async () => {
      const response = await getConfig();
      setForm((current) => ({ ...current, ...response.data }));
    };
    loadConfig();
  }, []);

  const handleChange = (event) => {
    const { name, value } = event.target;
    setForm((current) => ({ ...current, [name]: value }));
  };

  const handleSave = async () => {
    const response = await saveConfig(form);
    setStatus(response.data.message);
  };

  return (
    <Card>
      <CardContent>
        <Typography variant="h5" sx={{ mb: 2 }}>Configuration</Typography>
        {status ? <Alert severity="success" sx={{ mb: 2 }}>{status}</Alert> : null}
        <Grid container spacing={2}>
          <Grid item xs={12} md={6}><TextField fullWidth label="FTP Host" name="ftp_host" value={form.ftp_host} onChange={handleChange} /></Grid>
          <Grid item xs={12} md={6}><TextField fullWidth label="FTP Port" name="ftp_port" value={form.ftp_port} onChange={handleChange} /></Grid>
          <Grid item xs={12} md={6}><TextField fullWidth label="FTP User" name="ftp_user" value={form.ftp_user} onChange={handleChange} /></Grid>
          <Grid item xs={12} md={6}><TextField fullWidth label="FTP Password" name="ftp_password" type="password" value={form.ftp_password} onChange={handleChange} /></Grid>
          <Grid item xs={12} md={6}><TextField fullWidth label="FTP Path" name="ftp_path" value={form.ftp_path} onChange={handleChange} /></Grid>
          <Grid item xs={12} md={6}><TextField fullWidth label="Drive Folder" name="drive_folder" value={form.drive_folder} onChange={handleChange} /></Grid>
          <Grid item xs={12}><TextField fullWidth label="Sync Interval (minutes)" name="sync_interval" value={form.sync_interval} onChange={handleChange} /></Grid>
        </Grid>
        <Stack direction="row" spacing={2} sx={{ mt: 3 }}>
          <Button variant="contained" onClick={handleSave}>Save Settings</Button>
        </Stack>
      </CardContent>
    </Card>
  );
}

export default Settings;
